"use strict";(self.webpackChunkmagento2_hyva_jewellery_theme_docs=self.webpackChunkmagento2_hyva_jewellery_theme_docs||[]).push([[6535],{1661(t,e,n){n.r(e),n.d(e,{comp:()=>r,data:()=>i});var o=n(641);const s={},r=(0,n(6262).A)(s,[["render",function(t,e){return(0,o.uX)(),(0,o.CE)("div",null,[...e[0]||(e[0]=[(0,o.Fv)('<h1 id="split-content" tabindex="-1"><a class="header-anchor" href="#split-content"><span>Split Content</span></a></h1><p>The <strong>Split Content</strong> section shows an image on one side and text on the other side. Use it for a brand story, a featured collection, a service message, or a short jewellery promise.</p><h2 id="add-split-content" tabindex="-1"><a class="header-anchor" href="#add-split-content"><span>Add Split Content</span></a></h2><ol><li>Go to <strong>Content -&gt; Homepage Configurator -&gt; Sections</strong>.</li><li>Click <strong>Add New Section</strong>.</li><li>Enter a <strong>Title</strong>, for example <code>The Modern Heirloom Collection</code>.</li><li>Set <strong>Section Type</strong> to <strong>Split Content</strong>.</li><li>Set <strong>Enabled</strong> to <strong>Yes</strong>.</li><li>Use a <strong>Sort Order</strong> so it appears in the right place on the homepage.</li><li>Fill the <strong>Split Content Configuration</strong> fields.</li><li>Click <strong>Save</strong>.</li></ol><h2 id="content-settings" tabindex="-1"><a class="header-anchor" href="#content-settings"><span>Content settings</span></a></h2><table><thead><tr><th>Setting</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Image</strong></td><td>Upload the section image. Recommended size is <strong>800 x 900 px</strong>. Maximum file size is <strong>4 MB</strong>.</td></tr><tr><td><strong>Image Position</strong></td><td>Choose <strong>Left</strong> or <strong>Right</strong>.</td></tr><tr><td><strong>Badge Text</strong></td><td>Optional small badge, such as <code>New</code> or <code>Signature</code>.</td></tr><tr><td><strong>Heading</strong></td><td>Main heading. If empty, the section title is used.</td></tr><tr><td><strong>Body Text</strong></td><td>Short paragraph for the section.</td></tr><tr><td><strong>Button Label</strong></td><td>Button text, such as <code>Read Our Story</code>.</td></tr><tr><td><strong>Button URL</strong></td><td>Link for the button.</td></tr></tbody></table><h2 id="storefront-result" tabindex="-1"><a class="header-anchor" href="#storefront-result"><span>Storefront result</span></a></h2><p><img src="/screenshots/split-content-storefront-result.png" alt="Split content section on the storefront"></p><h2 id="good-practice" tabindex="-1"><a class="header-anchor" href="#good-practice"><span>Good practice</span></a></h2><ul><li>Keep the body text short.</li><li>Use one clear message.</li><li>Use <strong>Image Position</strong> to balance the page when you have many sections.</li><li>Check mobile view after saving.</li></ul>',10)])])}]]),i=JSON.parse('{"path":"/homepage/split-content.html","title":"Split Content","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Add Split Content","slug":"add-split-content","link":"#add-split-content","children":[]},{"level":2,"title":"Content settings","slug":"content-settings","link":"#content-settings","children":[]},{"level":2,"title":"Storefront result","slug":"storefront-result","link":"#storefront-result","children":[]},{"level":2,"title":"Good practice","slug":"good-practice","link":"#good-practice","children":[]}],"git":{"contributors":[{"name":"anikesh kumar","username":"","email":"anikesh.kumar204@webkul.in","commits":1}],"changelog":[{"hash":"65ee1538c72e98b02c838952f96993746b91fe68","time":1783608557000,"email":"anikesh.kumar204@webkul.in","author":"anikesh kumar","message":"init"}]},"filePathRelative":"homepage/split-content.md"}')}}]);